-- TABLES

CREATE TABLE blog_post_inventory_links (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  blog_post_id INTEGER NOT NULL,
  inventory_id INTEGER NOT NULL,
  keyword_matched TEXT NOT NULL,
  link_position INTEGER,
  created_at INTEGER NOT NULL DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)),
  FOREIGN KEY (blog_post_id) REFERENCES blog_posts(id) ON DELETE CASCADE,
  FOREIGN KEY (inventory_id) REFERENCES master_inventory(id) ON DELETE CASCADE,
  UNIQUE(blog_post_id, inventory_id)
);

CREATE TABLE blog_posts (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  slug TEXT UNIQUE NOT NULL,
  title TEXT NOT NULL,
  subtitle TEXT,
  body TEXT DEFAULT '',
  cover_image TEXT,
  author TEXT DEFAULT 'Frame & Reel',
  status TEXT DEFAULT 'draft',
  published_at INTEGER,
  created_at INTEGER NOT NULL,
  updated_at INTEGER NOT NULL
, tags TEXT DEFAULT '', featured INTEGER DEFAULT 0, theme TEXT DEFAULT '');

CREATE TABLE catalog (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  title_english TEXT NOT NULL,
  title_local TEXT,
  director TEXT,
  year INTEGER,
  synopsis TEXT,
  tmdb_id TEXT,
  genre TEXT,
  main_cast TEXT,
  created_at INTEGER NOT NULL DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)),
  updated_at INTEGER NOT NULL DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)),
  UNIQUE(title_english, director, year)
);

CREATE TABLE contact_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, email TEXT NOT NULL, message TEXT NOT NULL, name TEXT, created_at INTEGER);

CREATE TABLE distributor_registry (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, country TEXT, is_modern_reissue INTEGER DEFAULT 0, logo_patterns TEXT, known_codes TEXT, created_at INTEGER DEFAULT (strftime('%s', 'now') * 1000));

CREATE TABLE ebay_auth (id INTEGER PRIMARY KEY CHECK (id = 1), access_token TEXT, refresh_token TEXT, expires_at INTEGER, seller_username TEXT);

CREATE TABLE ebay_listings (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  inventory_id INTEGER REFERENCES inventory(id),
  ebay_item_id TEXT UNIQUE,
  ebay_status TEXT DEFAULT 'active',
  parsed_english_title TEXT,
  parsed_original_title TEXT,
  parsed_year INTEGER,
  parsed_release_year INTEGER,
  parsed_director TEXT,
  parsed_actors TEXT,
  parsed_format TEXT,
  parsed_artist TEXT,
  parsed_condition TEXT,
  parsed_country TEXT,
  raw_description TEXT,
  created_at INTEGER,
  ended_at INTEGER,
  updated_at INTEGER
);

CREATE TABLE entity_tags (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  tag_id INTEGER NOT NULL,
  entity_type TEXT NOT NULL CHECK(entity_type IN ('inventory', 'blog', 'image')),
  entity_id INTEGER NOT NULL,
  approved INTEGER NOT NULL DEFAULT 0,
  suggested_by TEXT DEFAULT 'manual',
  created_at INTEGER NOT NULL DEFAULT (cast(unixepoch('subsecond') * 1000 as integer))
);

