CREATE TABLE provenance_audits (id INTEGER PRIMARY KEY AUTOINCREMENT, poster_id INTEGER NOT NULL, tier1_title TEXT, tier1_confidence REAL, tier2_director_id TEXT, tier2_actor_ids TEXT, tier2_year INTEGER, tier2_confidence REAL, tier3_distributor TEXT, tier3_printer_credit TEXT, tier3_tax_codes TEXT, tier3_confidence REAL, overall_confidence REAL DEFAULT 0, edition_status TEXT DEFAULT 'unknown', provenance_conflict INTEGER DEFAULT 0, audit_notes TEXT, created_at INTEGER DEFAULT (strftime('%s', 'now') * 1000), updated_at INTEGER DEFAULT (strftime('%s', 'now') * 1000), FOREIGN KEY(poster_id) REFERENCES posters(id));

